  function parseEnvFile(): Record<string, string> {
    if (!existsSync(ENV_PATH)) return {};
    const result: Record<string, string> = {};
    for (const line of readFileSync(ENV_PATH, 'utf-8').split('\n')) {
      const trimmed = line.trim();
      if (!trimmed || trimmed.startsWith('#')) continue;
      const eqIdx = trimmed.indexOf('=');
      if (eqIdx === -1) continue;
      const key = trimmed.slice(0, eqIdx);
      let val = trimmed.slice(eqIdx + 1);
      if ((val.startsWith('"') && val.endsWith('"')) || (val.startsWith("'") && val.endsWith("'"))) {
        val = val.slice(1, -1);
      }
      result[key] = val;
    }
    return result;
  }

  function writeEnvValue(key: string, value: string): void {
    let content = existsSync(ENV_PATH) ? readFileSync(ENV_PATH, 'utf-8') : '';
    const re = new RegExp(`^${key}=.*$`, 'm');
    if (re.test(content)) {
      content = content.replace(re, `${key}=${value}`);
    } else {
      content = content.trimEnd() + `\n${key}=${value}\n`;
    }
    writeFileSync(ENV_PATH, content);
  }

  app.get('/api/settings', (_req, res) => {
    try {
      const env = parseEnvFile();
      const groups = CONFIG_GROUPS.map(g => ({
        label: g.label,
        fields: g.keys.map(k => ({
          key: k.key,
          label: k.label,
          hint: k.hint,
          type: k.type ?? 'text',
          value: env[k.key] ?? '',
          masked: maskValue(k.key, env[k.key] ?? ''),
          isSet: k.key in env && env[k.key] !== '',
        })),
      }));

      // Discover custom env vars not covered by CONFIG_GROUPS
      const knownKeys = new Set(CONFIG_GROUPS.flatMap(g => g.keys.map(k => k.key)));
      const customKeys = Object.keys(env).filter(k => !knownKeys.has(k));
      if (customKeys.length > 0) {
        groups.push({
          label: 'Custom / Other',
          fields: customKeys.map(k => {
            const isSensitive = SENSITIVE_PATTERNS.some(p => k.toUpperCase().includes(p));
            return {
              key: k,
              label: k,
              hint: 'Custom environment variable',
              type: isSensitive ? 'password' : 'text',
              value: env[k],
              masked: maskValue(k, env[k]),
              isSet: true,
            };
          }),
        });
      }

      res.json({ groups });
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  app.put('/api/settings/:key', async (req, res) => {
    try {
      const { key } = req.params;
      const { value } = req.body;
      if (typeof value !== 'string') {
        res.status(400).json({ error: 'value must be a string' });
        return;
      }
      // Allow known keys + any valid env var name (A-Z, 0-9, _)
      if (!/^[A-Za-z_][A-Za-z0-9_]*$/.test(key)) {
        res.status(400).json({ error: `Invalid key format: ${key}` });
        return;
      }
      writeEnvValue(key, value);

      // Apply runtime-hot settings immediately (no restart needed)
      if (key === 'ENABLE_1M_CONTEXT') {
        const { setEnable1MContext } = await import('../config.js');
        setEnable1MContext(value.toLowerCase() === 'true');
      }

      res.json({ ok: true, message: `Updated ${key}` });
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  app.delete('/api/settings/:key', (req, res) => {
    try {
      const { key } = req.params;
      if (!existsSync(ENV_PATH)) {
        res.status(404).json({ error: '.env file not found' });
        return;
      }
      let content = readFileSync(ENV_PATH, 'utf-8');
      const re = new RegExp(`^${key}=.*\n?`, 'm');
      content = content.replace(re, '');
      writeFileSync(ENV_PATH, content);
      res.json({ ok: true, message: `Removed ${key}` });
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  // ── Unleashed detail route ──────────────────────────────────────────

  app.get('/api/unleashed/:name/status', (req, res) => {
    const taskName = req.params.name.replace(/[^a-zA-Z0-9_-]/g, '_');
    const statusFile = path.join(BASE_DIR, 'unleashed', taskName, 'status.json');
    if (!existsSync(statusFile)) {
      res.status(404).json({ error: 'Unleashed task not found' });
      return;
    }
    try {
      const status = JSON.parse(readFileSync(statusFile, 'utf-8'));

      // Read recent progress entries
      const progressFile = path.join(BASE_DIR, 'unleashed', taskName, 'progress.jsonl');
      const progressEntries: Array<Record<string, unknown>> = [];
      if (existsSync(progressFile)) {
        const lines = readFileSync(progressFile, 'utf-8').trim().split('\n').filter(Boolean);
        for (const line of lines.slice(-20)) {
          try { progressEntries.push(JSON.parse(line)); } catch { /* skip */ }
        }
      }

      // Compute elapsed and remaining
      const elapsed = status.startedAt
        ? Math.round((Date.now() - new Date(status.startedAt).getTime()) / 60000)
        : 0;
      const remaining = status.maxHours && status.startedAt
        ? Math.max(0, Math.round(status.maxHours * 60 - elapsed))
        : null;

      res.json({ ...status, elapsed, remaining, progress: progressEntries });
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  // ── Profile routes ─────────────────────────────────────────────────

  app.get('/api/profiles', gwHandler(async (gw, _req, res) => {
    // Phase 14: previously checked the legacy profilesDir; now that the
    // legacy fallback is gone, AgentManager.listAll() returns [] when
    // AGENTS_DIR is missing or empty. No separate guard needed.
    const pm = new AgentManager(AGENTS_DIR);
    const profiles = pm.listAll().map(p => ({
      slug: p.slug,
      name: p.name,
      description: p.description,
    }));

    const activeSlug = gw.getSessionProfile('dashboard:web') ?? null;
    res.json({ profiles, active: activeSlug });
  }));

  app.post('/api/profiles/switch', async (req, res) => {
    try {
      const { slug } = req.body;
      const gateway = await getGateway();

      // Clear existing session so profile change takes effect cleanly
      gateway.clearSession('dashboard:web');

      if (slug) {
        gateway.setSessionProfile('dashboard:web', slug);
        res.json({ ok: true, message: `Switched to profile: ${slug}` });
      } else {
        // Clear profile (back to default)
        gateway.setSessionProfile('dashboard:web', '');
        res.json({ ok: true, message: 'Profile cleared — using default personality' });
      }
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  // ── Chat route ────────────────────────────────────────────────────

  app.post('/api/chat', async (req, res) => {
    const { message } = req.body;
    if (!message || typeof message !== 'string') {
      res.status(400).json({ error: 'message is required' });
      return;
    }
    try {
      const gateway = await getGateway();
      const response = await gateway.handleMessage('dashboard:web', message);
      // Outbound credential redaction — same defense applied at the channel
      // edges. Dashboard is admin-only but a leaked credential in chat output
      // could still end up in browser history, screenshots, etc.
      const { redactSecrets } = await import('../security/redact.js');
      const { text: redacted } = redactSecrets(response ?? '');

      // Attach the recall trace that powered this answer (if memory was used).
      // Lets the chat UI render a "🧠 N sources" affordance on each assistant
      // message, expandable to the chunks retrieved + their scores.
      let trace: {
        id: number;
        query: string;
        retrievedAt: string;
        chunkCount: number;
      } | null = null;
      try {
        const store = (gateway as any).assistant?.memoryStore;
        if (store?.getRecentRecallTraces) {
          const traces = store.getRecentRecallTraces('dashboard:web', 1);
          if (traces.length > 0) {
            trace = {
              id: traces[0].id,
              query: traces[0].query,
              retrievedAt: traces[0].retrievedAt,
              chunkCount: traces[0].chunkIds.length,
            };
          }
        }
      } catch { /* trace is optional */ }

      res.json({ ok: true, response: redacted, trace });
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  // ── Recall trace expansion (per-message memory provenance) ─────────
  // Returns the chunks that were retrieved for a specific trace, with their
  // scores and provenance (source_file, section, derived_from for summaries).
  app.get('/api/recall-traces/:id', async (req, res) => {
    try {
      const id = Number(req.params.id);
      if (!Number.isFinite(id) || id <= 0) {
        res.status(400).json({ error: 'invalid trace id' });
        return;
      }
      const gateway = await getGateway();
      const store = (gateway as any).assistant?.memoryStore;
      if (!store?.getRecallTrace) {
        res.status(503).json({ error: 'Memory store not available' });
        return;
      }
      const trace = store.getRecallTrace(id);
      if (!trace) {
        res.status(404).json({ error: 'trace not found' });
        return;
      }
      res.json({ ok: true, trace });
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  // List recent recall traces for a session (default: dashboard:web).
  // Powers a future "Memory Trace" tab on session detail; also useful for
  // CLI inspection.
  app.get('/api/recall-traces', async (req, res) => {
    try {
      const sessionKey = String(req.query.sessionKey ?? 'dashboard:web');
      const limit = Math.min(Math.max(Number(req.query.limit) || 20, 1), 200);
      const gateway = await getGateway();
      const store = (gateway as any).assistant?.memoryStore;
      if (!store?.getRecentRecallTraces) {
        res.json({ traces: [] });
        return;
      }
      const traces = store.getRecentRecallTraces(sessionKey, limit);
      res.json({ ok: true, sessionKey, traces });
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  // ── User mental model (MemGPT-style core memory) ─────────────────
  // Always-in-context surface. Slots: user_facts, goals, relationships,
  // agent_persona. agent_slug=null is the global block; per-agent overrides
  // layer on top in agent context.

  app.get('/api/user-model', async (req, res) => {
    try {
      const agentSlug = req.query.agentSlug ? String(req.query.agentSlug) : null;
      const gateway = await getGateway();
      const store = (gateway as any).assistant?.memoryStore;
      if (!store?.getAllUserModelBlocks) {
        res.status(503).json({ error: 'Memory store not available' });
        return;
      }
      const blocks = store.getAllUserModelBlocks(agentSlug);
      const slots = ['user_facts', 'goals', 'relationships', 'agent_persona'];
      // Always return a row for each slot (empty if unset) so the UI can render
      // editable textareas without special-casing missing slots.
      const merged = slots.map((slot: string) => {
        const found = blocks.find((b: any) => b.slot === slot);
        return found ?? {
          slot,
          content: '',
          charLimit: 2000,
          agentSlug: null,
          updatedAt: null,
        };
      });
      res.json({ ok: true, agentSlug, blocks: merged });
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  app.put('/api/user-model/:slot', async (req, res) => {
    try {
      const slot = String(req.params.slot);
      const validSlots = ['user_facts', 'goals', 'relationships', 'agent_persona'];
      if (!validSlots.includes(slot)) {
        res.status(400).json({ error: 'invalid slot' });
        return;
      }
      const content = String(req.body?.content ?? '');
      const agentSlug = req.body?.agentSlug ? String(req.body.agentSlug) : null;
      const gateway = await getGateway();
      const store = (gateway as any).assistant?.memoryStore;
      if (!store?.setUserModelBlock) {
        res.status(503).json({ error: 'Memory store not available' });
        return;
      }
      const result = store.setUserModelBlock({ slot, content, agentSlug });
      res.json({ ok: true, ...result });
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  app.delete('/api/user-model/:slot', async (req, res) => {
    try {
      const slot = String(req.params.slot);
      const agentSlug = req.query.agentSlug ? String(req.query.agentSlug) : null;
      const gateway = await getGateway();
      const store = (gateway as any).assistant?.memoryStore;
      if (!store?.deleteUserModelBlock) {
        res.status(503).json({ error: 'Memory store not available' });
        return;
      }
      const removed = store.deleteUserModelBlock(slot, agentSlug);
      res.json({ ok: true, removed });
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  // Seed the user model from existing memory — one-shot Haiku pass over
  // MEMORY.md, top-salience chunks, and recent session summaries. Returns
  // proposed values for each slot; the dashboard UI shows them in an
  // editable review panel before applying. Nothing is written to
  // user_model_blocks until the user clicks "Apply" on a slot.
  app.post('/api/user-model/seed', async (_req, res) => {
    try {
      const gateway = await getGateway();
      const store = (gateway as any).assistant?.memoryStore;
      if (!store) {
        res.status(503).json({ error: 'Memory store not available' });
        return;
      }
      // Build the LLM caller using the same Claude Agent SDK pattern as
      // periodic memory consolidation (see src/index.ts:684).
      const { query } = await import('@anthropic-ai/claude-agent-sdk');
      const llmCall = async (prompt: string): Promise<string> => {
        try {
          let result = '';
          const stream = query({
            prompt,
            options: {
              model: 'claude-haiku-4-5-20251001',
              maxTurns: 1,
              systemPrompt: 'You are a memory consolidation assistant. Extract only facts directly evidenced by the corpus. Be terse. Output exactly the requested format.',
            },
          });
          for await (const msg of stream) {
            if ((msg as { type?: string }).type === 'result') {
              result = (msg as { result?: string }).result ?? '';
            }
          }
          return result;
        } catch {
          return '';
        }
      };

      const { seedUserModelFromMemory } = await import('../memory/seed-user-model.js');
      const proposals = await seedUserModelFromMemory(store, llmCall);
      res.json({ ok: true, proposals });
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  // ── Memory chunk CRUD (dashboard curation) ───────────────────────
  // Lets the user fix wrong/stale memory directly from the search panel
  // instead of having to wait for auto-extraction to drift in the right
  // direction. Soft-delete via deleted_at; FTS trigger keeps deleted
  // content out of search results.

  // Memory Health snapshot — single endpoint feeding the dashboard tab.
  // Read-only aggregate over the existing tables; no caching needed (cheap).
  app.get('/api/memory/health', async (_req, res) => {
    try {
      const gateway = await getGateway();
      const store = (gateway as any).assistant?.memoryStore;
      if (!store?.getMemoryHealth) {
        res.status(503).json({ error: 'Memory store not available' });
        return;
      }
      const graphStore = (gateway as any).assistant?.graphStore;
      const health = store.getMemoryHealth({ graphStore, topCitedLimit: 10 });
      res.json({ ok: true, health });
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  app.post('/api/memory/health/action', async (req, res) => {
    try {
      const action = (req.body?.action ?? '') as string;
      const gateway = await getGateway();
      const store = (gateway as any).assistant?.memoryStore;
      if (!store) { res.status(503).json({ error: 'Memory store not available' }); return; }
      if (action === 'janitor') {
        const { runJanitor } = await import('../memory/maintenance.js');
        const result = runJanitor(store);
        res.json({ ok: true, action, result });
        return;
      }
      if (action === 'rebuild-fts' || action === 'fix-orphans') {
        const { runIntegrityProbes } = await import('../memory/integrity.js');
        const report = runIntegrityProbes(store);
        res.json({ ok: true, action, report });
        return;
      }
      res.status(400).json({ error: 'Unknown action: ' + action });
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  app.get('/api/memory/chunks/:id', async (req, res) => {
    try {
      const id = Number(req.params.id);
      if (!Number.isFinite(id) || id <= 0) {
        res.status(400).json({ error: 'invalid chunk id' });
        return;
      }
      const gateway = await getGateway();
      const store = (gateway as any).assistant?.memoryStore;
      if (!store?.getChunkDetail) {
        res.status(503).json({ error: 'Memory store not available' });
        return;
      }
      const chunk = store.getChunkDetail(id);
      if (!chunk) {
        res.status(404).json({ error: 'chunk not found' });
        return;
      }
      res.json({ ok: true, chunk });
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  app.put('/api/memory/chunks/:id', async (req, res) => {
    try {
      const id = Number(req.params.id);
      if (!Number.isFinite(id) || id <= 0) {
        res.status(400).json({ error: 'invalid chunk id' });
        return;
      }
      const body = (req.body ?? {}) as Record<string, unknown>;
      const gateway = await getGateway();
      const store = (gateway as any).assistant?.memoryStore;
      if (!store?.updateChunkContent) {
        res.status(503).json({ error: 'Memory store not available' });
        return;
      }
      const opts: {
        chunkId: number; content?: string; section?: string;
        category?: string | null; topic?: string | null; editedBy?: string | null;
      } = { chunkId: id, editedBy: 'dashboard' };
      if (typeof body.content === 'string') opts.content = body.content;
      if (typeof body.section === 'string') opts.section = body.section;
      if (body.category === null || typeof body.category === 'string') opts.category = body.category;
      if (body.topic === null || typeof body.topic === 'string') opts.topic = body.topic;
      const ok = store.updateChunkContent(opts);
      if (!ok) {
        res.status(404).json({ error: 'chunk not found' });
        return;
      }
      const chunk = store.getChunkDetail(id);
      res.json({ ok: true, chunk });
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  app.delete('/api/memory/chunks/:id', async (req, res) => {
    try {
      const id = Number(req.params.id);
      if (!Number.isFinite(id) || id <= 0) {
        res.status(400).json({ error: 'invalid chunk id' });
        return;
      }
      const gateway = await getGateway();
      const store = (gateway as any).assistant?.memoryStore;
      if (!store?.softDeleteChunk) {
        res.status(503).json({ error: 'Memory store not available' });
        return;
      }
      const removed = store.softDeleteChunk(id);
      res.json({ ok: true, removed });
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  app.post('/api/memory/chunks/:id/restore', async (req, res) => {
    try {
      const id = Number(req.params.id);
      if (!Number.isFinite(id) || id <= 0) {
        res.status(400).json({ error: 'invalid chunk id' });
        return;
      }
      const gateway = await getGateway();
      const store = (gateway as any).assistant?.memoryStore;
      if (!store?.restoreChunk) {
        res.status(503).json({ error: 'Memory store not available' });
        return;
      }
      const restored = store.restoreChunk(id);
      res.json({ ok: true, restored });
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  app.post('/api/memory/chunks/:id/pin', async (req, res) => {
    try {
      const id = Number(req.params.id);
      if (!Number.isFinite(id) || id <= 0) {
        res.status(400).json({ error: 'invalid chunk id' });
        return;
      }
      const pinned = !!(req.body?.pinned ?? true);
      const gateway = await getGateway();
      const store = (gateway as any).assistant?.memoryStore;
      if (!store?.setPinned) {
        res.status(503).json({ error: 'Memory store not available' });
        return;
      }
      const ok = store.setPinned(id, pinned);
      res.json({ ok: true, updated: ok, pinned });
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  app.get('/api/memory/chunks/:id/history', async (req, res) => {
    try {
      const id = Number(req.params.id);
      if (!Number.isFinite(id) || id <= 0) {
        res.status(400).json({ error: 'invalid chunk id' });
        return;
      }
      const limit = Math.min(Math.max(Number(req.query.limit) || 20, 1), 100);
      const gateway = await getGateway();
      const store = (gateway as any).assistant?.memoryStore;
      if (!store?.getChunkHistory) {
        res.status(503).json({ error: 'Memory store not available' });
        return;
      }
      const history = store.getChunkHistory(id, limit);
      res.json({ ok: true, history });
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  // ── Cron training chat endpoint ─────────────────────────────────────

  app.post('/api/cron/train', async (req, res) => {
    const { message, jobName, prompt, context, agentSlug } = req.body;
    if (!message || typeof message !== 'string') {
      res.status(400).json({ error: 'message is required' });
      return;
    }
    const sessionKey = `dashboard:cron-train:${jobName || 'new'}`;
    const agentLabel = agentSlug ? ` for agent "${agentSlug}"` : '';
    const currentState = `\n\n[CURRENT CRON STATE${agentLabel}]\nJob name: ${jobName || '(new)'}\nPrompt: ${prompt || '(empty)'}\nContext: ${context || '(none)'}\n`;
    const systemPrefix =
      `[CRON TRAINING MODE: You are helping the user refine a scheduled task${agentLabel}. ` +
      `The user wants to train/improve this cron job. Help them:\n` +
      `- Refine the prompt wording for clarity and effectiveness\n` +
      `- Add context, guidelines, or examples the agent should follow\n` +
      `- Think about edge cases and failure modes\n` +
      `- Suggest what reference files or data sources would help\n\n` +
      `When you suggest changes to the prompt or context, output them in a block so the user can apply them:\n` +
      '```suggested-prompt\nthe improved prompt text\n```\n' +
      '```suggested-context\nadditional context or guidelines\n```\n' +
      `Only include these blocks when you have a concrete suggestion. Keep the conversation natural — ask questions to understand what the cron should do.]${currentState}\n\n`;

    try {
      const gateway = await getGateway();
      const response = await gateway.handleMessage(sessionKey, systemPrefix + message);

      // Extract suggested-prompt and suggested-context blocks
      let suggestedPrompt = null;
      let suggestedContext = null;
      const promptMatch = response?.match(/```suggested-prompt\s*\n([\s\S]*?)```/);
      if (promptMatch) suggestedPrompt = promptMatch[1].trim();
      const contextMatch = response?.match(/```suggested-context\s*\n([\s\S]*?)```/);
      if (contextMatch) suggestedContext = contextMatch[1].trim();

      const cleanResponse = response
        ?.replace(/```suggested-prompt\s*\n[\s\S]*?```/g, '')
        ?.replace(/```suggested-context\s*\n[\s\S]*?```/g, '')
        ?.trim();

      res.json({ ok: true, response: cleanResponse, suggestedPrompt, suggestedContext });
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  // ── Builder chat endpoint ──────────────────────────────────────────

  // Track which builder sessions have received the full system prefix
  const builderSessionInited = new Set<string>();

  app.post('/api/builder/chat', async (req, res) => {
    const { message, artifactType, agentSlug, currentArtifact, attachments, linkedTools } = req.body;
    if (!message || typeof message !== 'string') {
      res.status(400).json({ error: 'message is required' });
      return;
    }
    const type = artifactType || 'skill';
    const sessionKey = `dashboard:builder:${type}:${agentSlug || 'clementine'}`;
    const isFirstMessage = !builderSessionInited.has(sessionKey);

    // ── Artifact state (compact JSON — no pretty-print to save tokens) ──
    const artifactContext = currentArtifact
      ? `\n[CURRENT ARTIFACT STATE]\n\`\`\`json-artifact\n${JSON.stringify(currentArtifact)}\n\`\`\`\n`
      : '';

    // ── File attachments — decode base64 text files and inject contents ──
    let fileContext = '';
    if (Array.isArray(attachments) && attachments.length > 0) {
      const fileParts: string[] = [];
      for (const att of attachments) {
        if (att.filename && att.content) {
          try {
            const decoded = Buffer.from(att.content, 'base64').toString('utf-8');
            // Cap each file at 4K chars to keep context reasonable
            const trimmed = decoded.length > 4000 ? decoded.slice(0, 4000) + '\n... (truncated)' : decoded;
            fileParts.push(`### ${att.filename}\n\`\`\`\n${trimmed}\n\`\`\``);
          } catch { /* skip binary files */ }
        }
      }
      if (fileParts.length > 0) {
        fileContext = `\n[REFERENCE FILES — the user attached these for context]\n${fileParts.join('\n\n')}\n`;
      }
    }

    // ── Linked tools context ──
    let toolContext = '';
    if (Array.isArray(linkedTools) && linkedTools.length > 0) {
      toolContext = `\n[LINKED TOOLS — this skill should use these tools: ${linkedTools.join(', ')}]\n`;
    }

    // ── Build the enriched message ──
    let enrichedMessage: string;

    if (isFirstMessage) {
      // Full system prefix on first message only
      const agentContext = agentSlug ? `You are building this for the agent "${agentSlug}". The skill/cron will be scoped to this agent specifically.\n` : '';
      const builderPrefix = type === 'skill'
        ? `[BUILDER MODE: You are helping build a reusable skill. ${agentContext}As you develop the procedure, output the current state as a JSON block:\n` +
          '```json-artifact\n{"type":"skill","title":"...","description":"...","triggers":["..."],"steps":"markdown procedure","toolsUsed":["tool1","tool2"]}\n```\n' +
          `Update this block in EVERY response as the skill evolves. If the user has linked tools, include them in the toolsUsed array. Ask clarifying questions to refine the procedure. Keep it conversational — one question at a time. ` +
          `When the user says "save" or approves, output the final artifact block.]\n\n`
        : type === 'cron'
        ? `[BUILDER MODE: You are helping build a scheduled cron job. As you develop the job, output the current state as a JSON block:\n` +
          '```json-artifact\n{"type":"cron","name":"...","schedule":"cron expression","tier":1,"prompt":"the full job prompt","mode":"standard","enabled":true}\n```\n' +
          `Update this block in EVERY response as the job evolves. Ask about schedule, what it should do, which tools/APIs it needs, what tier (1=read-only, 2=read-write), and whether it should run in unleashed mode.\n` +
          `IMPORTANT: Cron jobs automatically pull in matching skills (learned procedures) at runtime. If the user describes a workflow that should be reusable, suggest creating it as a skill first, then building the cron job that references those trigger keywords. This way the cron gets smarter over time as skills improve.\n` +
          `When the user says "save" or approves, output the final artifact block.]\n\n`
        : type === 'agent'
        ? `[BUILDER MODE: You are helping create a new AI agent team member. As you develop the agent config, output the current state as a JSON block:\n` +
          '```json-artifact\n{"type":"agent","name":"...","description":"role description","model":"sonnet","personality":"system prompt / onboarding brief","tools":["tool1","tool2"],"channel":"","tier":2}\n```\n' +
          `Update this block in EVERY response as the agent evolves. Ask about: the agent's role, what tools it needs, what model to use (haiku/sonnet/opus), its personality/system prompt, which channel it should operate in, and its security tier.\n` +
          `Help the user think about what makes a good agent: clear role, specific tools, focused personality. Keep it conversational — one question at a time.\n` +
          `When the user says "save" or approves, output the final artifact block.]\n\n`
        : type === 'workflow'
        ? `[BUILDER MODE: You are helping build a multi-step workflow pipeline. As you develop the workflow, output the current state as a JSON block:\n` +
          '```json-artifact\n{"type":"workflow","name":"...","description":"...","schedule":"","steps":"step1:\\n  prompt: ...\\nstep2:\\n  prompt: ...\\n  dependsOn: step1"}\n```\n' +
          `Update this block in EVERY response as the workflow evolves. Ask about: what the workflow should accomplish, what steps are needed, which agents should run each step, dependencies between steps, and whether it should be triggered on a schedule or manually.\n` +
          `Workflows are defined as markdown files with YAML frontmatter. Each step has an id, prompt, optional agent, and optional dependsOn array.\n` +
          `When the user says "save" or approves, output the final artifact block.]\n\n`
        : `[BUILDER MODE: You are helping configure an artifact. Output structured JSON blocks as you build.]\n\n`;

      enrichedMessage = builderPrefix + fileContext + toolContext + artifactContext + message;
      builderSessionInited.add(sessionKey);
    } else {
      // Subsequent messages: just artifact state + files + tools + user message (no repeated prefix)
      enrichedMessage = fileContext + toolContext + artifactContext + message;
    }

    try {
      const gateway = await getGateway();
      const response = await gateway.handleMessage(sessionKey, enrichedMessage);

      // Parse any json-artifact blocks from the response
      let artifact = null;
      const artifactMatch = response?.match(/```json-artifact\s*\n([\s\S]*?)```/);
      if (artifactMatch) {
        try { artifact = JSON.parse(artifactMatch[1]); } catch { /* malformed */ }
      }

      // Strip the artifact block from the display response
      const cleanResponse = response?.replace(/```json-artifact\s*\n[\s\S]*?```/g, '').trim();

      res.json({ ok: true, response: cleanResponse, artifact });
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  // Reset builder session when user clicks "New"
  app.post('/api/builder/reset', (_req, res) => {
    const { artifactType, agentSlug } = _req.body;
    const type = artifactType || 'skill';
    const sessionKey = `dashboard:builder:${type}:${agentSlug || 'clementine'}`;
    builderSessionInited.delete(sessionKey);
    res.json({ ok: true });
  });

  // Test a skill by sending a trigger message through the gateway with skill context
  app.post('/api/builder/test', async (req, res) => {
    try {
      const { artifact, testMessage } = req.body;
      if (!artifact?.title || !artifact?.steps) {
        res.status(400).json({ error: 'Skill artifact with title and steps is required' });
        return;
      }
      const trigger = testMessage || (artifact.triggers?.[0] ? `I need to ${artifact.triggers[0]}` : `Help me with ${artifact.title}`);

      // Build a test prompt that injects the skill as context
      let skillContext = `## Skill Being Tested: ${artifact.title}\n\n${artifact.description || ''}\n\n## Procedure\n\n${artifact.steps}`;
      if (artifact.toolsUsed?.length) {
        skillContext += `\n\n**Tools for this skill:** ${artifact.toolsUsed.join(', ')}`;
      }
      const testPrompt = `[SKILL TEST MODE — You have a skill loaded. Use the procedure below to respond to the user's message. This is a dry-run test so describe what you would do at each step rather than actually executing tools.]\n\n${skillContext}\n\n${trigger}`;

      const gateway = await getGateway();
      const sessionKey = 'dashboard:builder:test';
      const response = await gateway.handleMessage(sessionKey, testPrompt);

      res.json({ ok: true, response: response || '(no response)', trigger });
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  // Save completed builder artifact
  app.post('/api/builder/save', (req, res) => {
    try {
      const { artifactType, artifact, agentSlug, attachments } = req.body;
      if (!artifact) { res.status(400).json({ error: 'artifact is required' }); return; }

      if (artifactType === 'skill') {
        // Scope to agent if selected, otherwise global
        const skillsDir = agentSlug
          ? path.join(VAULT_DIR, '00-System', 'agents', agentSlug, 'skills')
          : path.join(VAULT_DIR, '00-System', 'skills');
        if (!existsSync(skillsDir)) mkdirSync(skillsDir, { recursive: true });
        const name = (artifact.title || 'untitled').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 60);
        const now = new Date().toISOString();
        const matterMod = require('gray-matter');

        // Backup existing skill before overwrite + preserve runtime stats
        const existingPath = path.join(skillsDir, `${name}.md`);
        let existingUseCount = 0;
        let existingCreatedAt = now;
        if (existsSync(existingPath)) {
          copyFileSync(existingPath, existingPath.replace(/\.md$/, '.md.bak'));
          try {
            const prev = matterMod(readFileSync(existingPath, 'utf-8'));
            existingUseCount = prev.data.useCount ?? 0;
            existingCreatedAt = prev.data.createdAt ?? now;
          } catch { /* use defaults */ }
        }

        const meta: Record<string, unknown> = {
          title: artifact.title, description: artifact.description || '', triggers: artifact.triggers || [],
          source: 'builder', toolsUsed: artifact.toolsUsed || [], useCount: existingUseCount, createdAt: existingCreatedAt, updatedAt: now,
        };
        if (agentSlug) meta.agentSlug = agentSlug;

        // Persist attached reference files alongside the skill
        const attachmentNames: string[] = [];
        if (Array.isArray(attachments) && attachments.length > 0) {
          const skillAttDir = path.join(skillsDir, name + '.files');
          if (!existsSync(skillAttDir)) mkdirSync(skillAttDir, { recursive: true });
          for (const att of attachments) {
            if (att.filename && att.content) {
              try {
                const safeName = att.filename.replace(/[^a-zA-Z0-9._-]/g, '_');
                writeFileSync(path.join(skillAttDir, safeName), Buffer.from(att.content, 'base64'));
                attachmentNames.push(safeName);
              } catch { /* skip bad files */ }
            }
          }
        }
        if (attachmentNames.length > 0) meta.attachments = attachmentNames;

        const content = matterMod.stringify(
          `\n# ${artifact.title}\n\n${artifact.description || ''}\n\n## Procedure\n\n${artifact.steps || ''}\n`,
          meta,
        );
        writeFileSync(path.join(skillsDir, `${name}.md`), content);
        const scope = agentSlug ? ` (for ${agentSlug})` : ' (global)';
        res.json({ ok: true, name, message: `Skill "${artifact.title}" saved${scope}` });
      } else if (artifactType === 'cron') {
        // Scope cron to agent if selected
        const jobName = agentSlug && !artifact.name.startsWith(agentSlug + ':')
          ? `${agentSlug}:${artifact.name}`
          : artifact.name;
        const { cronFile } = agentSlug
          ? (() => {
              const agentCronFile = path.join(VAULT_DIR, '00-System', 'agents', agentSlug, 'CRON.md');
              return { cronFile: existsSync(agentCronFile) ? agentCronFile : path.join(VAULT_DIR, '00-System', 'CRON.md') };
            })()
          : { cronFile: path.join(VAULT_DIR, '00-System', 'CRON.md') };
        if (!existsSync(cronFile)) { res.status(500).json({ error: 'CRON.md not found' }); return; }
        const matterMod = require('gray-matter');
        const parsed = matterMod(readFileSync(cronFile, 'utf-8'));
        const jobs = parsed.data.jobs || [];
        jobs.push({
          name: jobName,
          schedule: artifact.schedule,
          prompt: artifact.prompt,
          tier: artifact.tier || 1,
          enabled: artifact.enabled !== false,
          ...(agentSlug ? { agent: agentSlug } : {}),
          ...(artifact.mode === 'unleashed' ? { mode: 'unleashed', max_hours: artifact.max_hours || 1 } : {}),
          ...(artifact.work_dir ? { work_dir: artifact.work_dir } : {}),
        });
        parsed.data.jobs = jobs;
        writeFileSync(cronFile, matterMod.stringify(parsed.content, parsed.data));
        res.json({ ok: true, name: jobName, message: `Cron job "${jobName}" saved` });
      } else if (artifactType === 'agent') {
        // Create agent via the same mechanism as the manual form
        const slug = (artifact.name || 'new-agent').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 40);
        const agentDir = path.join(VAULT_DIR, '00-System', 'agents', slug);
        if (!existsSync(agentDir)) mkdirSync(agentDir, { recursive: true });
        const config = {
          name: artifact.name || slug,
          description: artifact.description || '',
          model: artifact.model || '',
          personality: artifact.personality || '',
          allowedTools: artifact.tools || [],
          tier: artifact.tier || 2,
          channel: artifact.channel || '',
          canMessage: [],
          status: 'active',
        };
        writeFileSync(path.join(agentDir, 'config.json'), JSON.stringify(config, null, 2));
        // Create empty CRON.md for the agent
        const agentCronFile = path.join(agentDir, 'CRON.md');
        if (!existsSync(agentCronFile)) {
          writeFileSync(agentCronFile, '---\njobs: []\n---\n');
        }
        res.json({ ok: true, name: slug, message: `Agent "${artifact.name}" created` });
      } else if (artifactType === 'workflow') {
        // Save workflow as markdown file
        const wfDir = path.join(VAULT_DIR, '00-System', 'workflows');
        if (!existsSync(wfDir)) mkdirSync(wfDir, { recursive: true });
        const wfName = (artifact.name || 'new-workflow').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 60);
        const matterMod = require('gray-matter');
        const meta: Record<string, unknown> = {
          name: artifact.name || wfName,
          description: artifact.description || '',
          enabled: true,
          ...(artifact.schedule ? { trigger: { schedule: artifact.schedule } } : {}),
        };
        const content = matterMod.stringify(
          `\n# ${artifact.name || wfName}\n\n${artifact.description || ''}\n\n## Steps\n\n${artifact.steps || ''}\n`,
          meta,
        );
        writeFileSync(path.join(wfDir, `${wfName}.md`), content);
        res.json({ ok: true, name: wfName, message: `Workflow "${artifact.name}" saved` });
      } else {
        res.status(400).json({ error: `Unknown artifact type: ${artifactType}` });
      }
    } catch (err) {
      res.status(500).json({ error: String(err) });
    }
  });

  // ── Memory search route ───────────────────────────────────────────

  app.get('/api/memory/search', async (req, res) => {
    const q = String(req.query.q ?? '');
    if (!q.trim()) {
      res.json({ results: [] });
      return;
    }
    try {
      const data = await searchMemory(q, 20);

      // Enrich with graph relationships for entities found in results
      let graphContext: Array<{ from: string; rel: string; to: string }> = [];
      try {
        const { getSharedGraphStore } = await import('../memory/graph-store.js');
        const graphDbDir = path.join(BASE_DIR, '.graph.db');
        const gs = await getSharedGraphStore(graphDbDir);
        if (gs) {
          const entityIds = new Set<string>();
          // Extract entity slugs from result source files
          for (const r of (data.results ?? []) as Array<Record<string, unknown>>) {
            const sf = String(r.source_file ?? '');
            if (/0[2-4]-/.test(sf)) {
              entityIds.add(path.basename(sf, '.md').toLowerCase().replace(/\s+/g, '-'));
            }
          }
          // Also try query terms
          for (const word of q.toLowerCase().split(/\s+/)) {
            const clean = word.replace(/[^a-z0-9-]/g, '');
            if (clean.length >= 3) entityIds.add(clean);
          }
          const seen = new Set<string>();
          for (const id of [...entityIds].slice(0, 5)) {
            const rels = await gs.getRelationships(id, 'both');
            for (const r of rels.slice(0, 5)) {
              const key = `${r.from}-${r.type}-${r.to}`;
              if (!seen.has(key)) {
                seen.add(key);
                graphContext.push({ from: r.from, rel: r.type, to: r.to });
              }
            }
          }
        }
      } catch { /* graph unavailable */ }

      res.json({ ...data, graphContext });
    } catch (err) {
      res.status(500).json({ results: [], error: String(err) });
    }
  });

  // ── Metrics route ─────────────────────────────────────────────────

  app.get('/api/metrics', (_req, res) => {
    res.json(computeMetrics());
  });

  // ── Tool-usage analytics (Phase 11/11b) ─────────────────────────
  // Surfaces the same per-family cost + call breakdown the CLI report
  // shows. Window defaults to last 24h; ?hours=N for longer windows.
  app.get('/api/analytics/tool-usage', async (req, res) => {
    try {
      const { buildToolUsageReport, defaultAuditLogPath } =
        await import('../analytics/tool-usage.js');
      const hoursRaw = String(req.query.hours ?? '24');
      const hours = Math.max(1, Math.min(168, parseInt(hoursRaw, 10) || 24));
      const end = new Date();
      const start = new Date(end.getTime() - hours * 60 * 60 * 1000);
      const report = buildToolUsageReport(
        defaultAuditLogPath(BASE_DIR),
        start.toISOString(),
        end.toISOString(),
      );
      res.json({ ok: true, hours, ...report });
    } catch (err) {
      res.status(500).json({ ok: false, error: String(err) });
    }
  });

  // ── Token Usage API ──────────────────────────────────────────────

  app.get('/api/metrics/usage', async (_req, res) => {
    if (!existsSync(MEMORY_DB_PATH)) {
      res.json({ error: 'No DB', totalTokens: 0, byModel: [], bySource: [], byDay: [] });
      return;
    }
    const Database = (await import('better-sqlite3')).default;
    const db = new Database(MEMORY_DB_PATH, { readonly: true });
    try {
      // Check if table exists
      const tableExists = db.prepare(
        "SELECT name FROM sqlite_master WHERE type='table' AND name='usage_log'",
      ).get();
      if (!tableExists) {
        res.json({ totalTokens: 0, totalInput: 0, totalOutput: 0, byModel: [], bySource: [], byDay: [] });
        return;
      }

      const totals = db.prepare(
        `SELECT COALESCE(SUM(input_tokens), 0) as ti, COALESCE(SUM(output_tokens), 0) as to_,
                COALESCE(SUM(cache_read_tokens), 0) as tcr, COALESCE(SUM(cache_creation_tokens), 0) as tcc
         FROM usage_log`,
      ).get() as { ti: number; to_: number; tcr: number; tcc: number };

      const byModel = db.prepare(
        `SELECT model, SUM(input_tokens) as input, SUM(output_tokens) as output, SUM(cache_read_tokens) as cacheRead
         FROM usage_log GROUP BY model ORDER BY input DESC`,
      ).all();

      const bySource = db.prepare(
        `SELECT source, SUM(input_tokens) as input, SUM(output_tokens) as output
         FROM usage_log GROUP BY source ORDER BY input DESC`,
      ).all();

      const byDay = db.prepare(
        `SELECT date(created_at) as day, SUM(input_tokens) as input, SUM(output_tokens) as output
         FROM usage_log WHERE created_at >= date('now', '-7 days')
         GROUP BY date(created_at) ORDER BY day`,
      ).all();

      res.json({
        totalInput: totals.ti,
        totalOutput: totals.to_,
        totalCacheRead: totals.tcr,
        totalCacheCreation: totals.tcc,
        totalTokens: totals.ti + totals.to_,
        byModel,
        bySource,
        byDay,
      });
    } catch (err) {
      res.json({ error: String(err), totalTokens: 0, byModel: [], bySource: [], byDay: [] });
    } finally {
      db.close();
    }
  });

  // ── Session Detail API ───────────────────────────────────────────

  app.get('/api/sessions/:key/messages', async (req, res) => {
    const sessionKey = req.params.key;
    if (!existsSync(MEMORY_DB_PATH)) {
      res.json({ messages: [], source: 'none' });
      return;
    }
    const Database = (await import('better-sqlite3')).default;
    const db = new Database(MEMORY_DB_PATH, { readonly: true });
    try {
      const tableExists = db.prepare(
        "SELECT name FROM sqlite_master WHERE type='table' AND name='transcripts'",
      ).get();
      if (!tableExists) {
        res.json({ messages: [], source: 'none' });
        return;
      }
      const rows = db.prepare(
        `SELECT session_key, role, content, model, created_at
         FROM transcripts WHERE session_key = ? ORDER BY id LIMIT 200`,
      ).all(sessionKey) as Array<{
        session_key: string; role: string; content: string; model: string; created_at: string;
      }>;
      res.json({
        messages: rows.map(r => ({
          role: r.role,
          content: r.content,
          model: r.model,
          createdAt: r.created_at,
        })),
        source: 'transcripts',
      });
    } catch (err) {
      res.json({ messages: [], source: 'error', error: String(err) });
    } finally {
      db.close();
    }
  });

  app.get('/api/sessions/:key/usage', async (req, res) => {
    const sessionKey = req.params.key;
    if (!existsSync(MEMORY_DB_PATH)) {
      res.json({ totalTokens: 0, totalInput: 0, totalOutput: 0, numQueries: 0 });
      return;
    }
    const Database = (await import('better-sqlite3')).default;
    const db = new Database(MEMORY_DB_PATH, { readonly: true });
    try {
      const tableExists = db.prepare(
        "SELECT name FROM sqlite_master WHERE type='table' AND name='usage_log'",
      ).get();
      if (!tableExists) {
        res.json({ totalTokens: 0, totalInput: 0, totalOutput: 0, numQueries: 0 });
        return;
      }
      const row = db.prepare(
        `SELECT COALESCE(SUM(input_tokens), 0) as ti, COALESCE(SUM(output_tokens), 0) as to_,
                COUNT(*) as cnt
         FROM usage_log WHERE session_key = ?`,
      ).get(sessionKey) as { ti: number; to_: number; cnt: number };
      res.json({
        totalInput: row.ti,
        totalOutput: row.to_,
        totalTokens: row.ti + row.to_,
        numQueries: row.cnt,
      });
    } catch {
      res.json({ totalTokens: 0, totalInput: 0, totalOutput: 0, numQueries: 0 });
    } finally {
      db.close();
    }
  });

